import React from 'react';
import {Card} from 'react-bootstrap';


// Componentes
import List from '../../Components/List'


// Importando do Redux
import { useSelector } from 'react-redux'



const itemsPerPage = 10

const Curso = (props) => {

    const listaCursos = useSelector(state => state.listaCursos)
    const cursoSelecionado = useSelector(state => state.cursoSelecionado)

    let filtered = useSelector(state => state.listaCursosFiltrado)
    let cardTitle
    let pageTitle = 'Selecionar Curso de graduação'

    if(cursoSelecionado !== ""){
        cardTitle = <Card.Title as="h5">Curso selecionado: <b>{cursoSelecionado.NO_CINE_ROTULO}</b>. Para trocar, escolha um curso abaixo.</Card.Title>
        pageTitle = "Trocar Curso de graduação"
    }
    else
        cardTitle = <Card.Title as="h5">Selecione um curso de graduação</Card.Title>

    return (
        <List
            pageTitle={pageTitle}
            cardTitle={cardTitle}
            placeholder="Pesquise por um curso de graduação"
            itemsPerPage={itemsPerPage}
            data={listaCursos}
            dataFiltered={filtered}
            filterDispach='FILTER_COURSE'
            selectDispach='SELECT_COURSE'
        />
    )
}


export default Curso;